CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260124000015_InitialCreate') THEN
    CREATE TABLE "SearchQueries" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Keyword" character varying(500) NOT NULL,
        "Category" character varying(200),
        "IsActive" boolean NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_SearchQueries" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260124000015_InitialCreate') THEN
    CREATE TABLE "FoundTenders" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "ExternalId" character varying(200) NOT NULL,
        "PurchaseNumber" character varying(200) NOT NULL,
        "Title" character varying(1000) NOT NULL,
        "CustomerName" character varying(500),
        "PublishDate" timestamp with time zone,
        "DirectLinkToSource" character varying(1000),
        "FoundByQueryId" integer,
        "SavedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_FoundTenders" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_FoundTenders_SearchQueries_FoundByQueryId" FOREIGN KEY ("FoundByQueryId") REFERENCES "SearchQueries" ("Id") ON DELETE SET NULL
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260124000015_InitialCreate') THEN
    CREATE UNIQUE INDEX "IX_FoundTenders_ExternalId" ON "FoundTenders" ("ExternalId");
