DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260128011519_AddDocumentAndAnalysisModels') THEN
    CREATE TABLE "TenderDocuments" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "TenderId" integer NOT NULL,
        "DocType" character varying(100) NOT NULL,
        "PublishedAt" timestamp with time zone,
        "DownloadedAt" timestamp with time zone NOT NULL,
        "SourceJson" jsonb NOT NULL,
        "FilePath" character varying(500),
        CONSTRAINT "PK_TenderDocuments" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_TenderDocuments_FoundTenders_TenderId" FOREIGN KEY ("TenderId") REFERENCES "FoundTenders" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

