        CONSTRAINT "FK_TechnologyAnalyses_FoundTenders_TenderId" FOREIGN KEY ("TenderId") REFERENCES "FoundTenders" ("Id") ON DELETE CASCADE,
        CONSTRAINT "FK_TechnologyAnalyses_TenderDocuments_DocumentId" FOREIGN KEY ("DocumentId") REFERENCES "TenderDocuments" ("Id") ON DELETE SET NULL
